mapper.update:
UPDATE t_material_yard
SET deleted_flag = #{deletedFlag}
WHERE yard_id = #{yardId}

mapper.select:
SELECT *
FROM t_material_yard
WHERE yard_code = #{yardCode}
AND enterprise_id = #{enterpriseId}
AND deleted_flag = #{deletedFlag}

    AND yard_id != #{excludeYardId}

SELECT y.*
FROM t_material_yard y
LEFT JOIN t_employee e ON y.create_user_id = e.employee_id

    y.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(y.yard_name,#{queryForm.keywords}) OR INSTR(y.yard_code,#{queryForm.keywords})
        OR INSTR(y.contact,#{queryForm.keywords}) OR INSTR(y.contact_phone,#{queryForm.keywords})
        OR INSTR(y.create_user_name,#{queryForm.keywords}))


        AND y.enterprise_id = #{queryForm.enterpriseId}


        AND DATE_FORMAT(y.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(y.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        AND y.disabled_flag = #{queryForm.disabledFlag}



    ORDER BY y.create_time DESC

SELECT y.*
FROM t_material_yard y
WHERE y.yard_id = #{yardId}
  AND y.deleted_flag = #{deletedFlag}

SELECT *
FROM t_material_yard
WHERE deleted_flag = #{deletedFlag} AND disabled_flag = #{disabledFlag}
  AND enterprise_id = #{enterpriseId}
order by yard_id desc
